void
list_insert_item_before(list_t *l,
						list_item_t *next,
						list_item_t *i)
{
	if (l->head == next) {
		i->next = next;
		i->pred = NULL;
		l->head = i;
		next->pred = i;
	}
	else {
		i->next = next;
		i->pred = next->pred;
		next->pred->next = i;
		next->pred = i;
	}
	l->length++;
}

void
list_insert_item_after(list_t *l,
					   list_item_t *pred,
					   list_item_t *i)
{
	if (l->tail == pred) {
		i->pred = pred;
		i->next = NULL;
		l->tail = i;
		pred->next = i;
	}
	else {
		i->pred = pred;
		i->next = pred->next;
		pred->next->pred = i;
		pred->next = i;
	}
	l->length++;
}

void
list_insert_item_sorted(list_t *l,
						list_item_t *i)
{
	list_item_t *itr;

	if (l->head) {
		for (itr = l->head; itr && l->compare(list_item_get_datum(i),
