void
enqueue(node *new_node)
{
	node *c;
	if (queue == NULL) {
		queue = new_node;
		queue->next = NULL;
	}
	else {
		c = queue;
		while (c->next != NULL) {
			c = c->next;
		}
		c->next = new_node;
		new_node->next = NULL;
	}
}

node *
dequeue(void)
{
	node *n = queue;
	queue = queue->next;
	n->next = NULL;
	return n;
}

void
print_leaves(node *root)
{
